{
  "files": [
    {
      "path": "README.md",
      "content": "# Project Management API
This is a simple in-memory project management API built with Node.js and Express.
"
    },
    {
      "path": "package.json",
      "content": "{
  "name": "project-management-api",
  "version": "1.0.0",
  "description": "A simple in-memory project management API",
  "main": "src/server.js",
  "scripts": {
    "start": "node src/server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "supertest": "^6.3.3"
  }
}
"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const app = express();

app.use(express.json());

// Health endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Import project routes
const projectRoutes = require('./modules/projects/routes');
app.use('/projects', projectRoutes);

module.exports = { app };
"
    },
    {
      "path": "src/server.js",
      "content": "const { app } = require('./app');

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
"
    }
  ],
  "notes": "Added README.md and updated package.json to include supertest in dependencies. Ensured app.js imports project routes correctly."
}
